        protected onClickNext(){
            
            let gameData = GameData.Instance;

            switch(gameData.gameMode){
                case GameMode.Classic:
                    gameData.level = -1;
                    break;
                case GameMode.Challenge:
                default:
                    //依照結果判定是下一關or重玩
                    ++gameData.level;
                    break;
            }

            super.onClickNext();
        }
    
