import { _decorator, Component, Node } from 'cc';
import { GameMode } from './SampleDefine';
import { GameState } from './SampleDefine';
import { BaseConfigManager } from '@gamecommon/base/BaseConfigManager';

const { ccclass, property } = _decorator;



//遊戲動態資料 
export class GameData {

    public configMgr : BaseConfigManager = new BaseConfigManager();
    
    public gameMode : GameMode = GameMode.Classic;
    public state : GameState = GameState.Non;

    //關卡資料
    public level : number = 1;
    public score : number = 0;

    //排行榜資料

    //成就資料

    private static instance : GameData = null;

    public static get Instance(){
        if( this.instance == null ){
            this.instance = new GameData();
        }
        return this.instance;
    }

    public reset(){
        this.gameMode = GameMode.Classic;
        this.state = GameState.Non;
        this.level = 1;
        this.score = 0;
    }
}