import * as PlatformModule from '@gamecommon/base/PlatformModule';
import { CCBoolean } from 'cc';
import { Sprite } from 'cc';
import { CCString } from 'cc';
import { _decorator, Component, Node } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('SampleItemSpriteChanger')
export class SampleItemSpriteChanger extends Component {

    @property(CCString)
    itemId: string = '10000002';
    @property(CCBoolean)
    changeOnEnable: boolean = false;

    protected onEnable(): void {
        if (this.changeOnEnable) {
            this.changeSprite();
        }
    }

    changeSprite() {
        const item = PlatformModule.ItemFactory?.Instance.GetItemById(Number(this.itemId));
        if (item) {
            const sprite = this.node.getComponent(Sprite);
            sprite && item.GetImage(sprite);
        }
    }
    
}


