import { _decorator, Component, Node, EventTarget, EventTouch } from 'cc';
import { BaseGameEvent } from '@gamecommon/base/BaseGameEvent';
import { BaseGameEventDefine } from '@gamecommon/base/BaseGameDefine';
import { BaseGameLobby } from '@gamecommon/base/BaseGameLobby';
import { GameMode } from './SampleDefine';
import { GameData } from './SampleGameData';
import { BaseSoundMgr } from '@gamecommon/base/BaseSoundMgr';
import { BaseGameData } from '@gamecommon/base/BaseGameData';
import { SingleGameCollectionProgress } from '@gamecommon/single_game_collect_activity/ui/SingleGameCollectionProgress';
import { SingleGameCollectItemPopup } from '@gamecommon/single_game_collect_activity/ui/SingleGameCollectItemPopup';
import { SingleGameCollectActivityManager } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityManager';
import { SingleGameCollectActivityState } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityDataDefine';
const { ccclass, property } = _decorator;

@ccclass('SampleGameLobby')
export class SampleGameLobby extends BaseGameLobby {

    protected async onEnable() {
        const service = BaseGameData.Instance.Service;
        if (service) {
            await service.requestGameInfo();
        }
        super.onEnable();
    }

    protected onDisable() {
        super.onDisable();
    }

    //此prefab示範了轉場動畫的使用方式, 請見 SampleGameLobby prefab上設定
    
    public async onClickStartGame( event: EventTouch, mode? :string ){

        let gameData = GameData.Instance;
        switch(mode){
            case "challenge":
                gameData.gameMode = GameMode.Challenge;
                gameData.level = 1;
                break;
            case "classic":
            default:
                gameData.gameMode = GameMode.Classic;
                gameData.level = -1;
                break;
        }

        if (BaseGameData.Instance.Service) {
            const success = await BaseGameData.Instance.Service.requestGameStart(1, gameData.gameMode, gameData.level);
            if (!success) {
                return;
            }
        }
        
        this.startGame();
    }

    public onClickTestSound(event: EventTouch, key?: string) {
        BaseSoundMgr.Instance.PlaySound(key, false);
    }

    public onClickTestMusic(event: EventTouch, key?: string) {
        BaseSoundMgr.Instance.PlaySound(key, true);
    }
}
