import { _decorator, Label, Node, Prefab, Vec3 } from 'cc';
import { BaseGamePlay } from '@gamecommon/base/BaseGamePlay';
import { GameMode, GameState } from './SampleDefine';
import { GameData } from './SampleGameData';
import { BasePrefabMgr } from '@gamecommon/base/BasePrefabMgr';
import { BaseGameData } from '@gamecommon/base/BaseGameData';
const { ccclass, property } = _decorator;

@ccclass('SampleGamePlay')
export class SampleGamePlay extends BaseGamePlay {

    //遊戲玩法實作區, 可自行決定流程製作方式, 也可另外拆分成不同的Component

    @property(Prefab)
    private circlePrefab: Prefab = null;

    @property(Node)
    private circleRoot: Node = null;

    @property(Label)
    private btn:Label = null;

    @property(Label)
    private info:Label = null;

    private circle:Node[]= [];
    private gameData: GameData = null;
    private isPause: boolean = false;
    private rotateAngle: number = 0;

    protected onLoad(): void {
        super.onLoad();
        this.gameData = GameData.Instance;
    }

    public async enter(isContinue:boolean, arg?:any){
        super.enter(isContinue, arg);
        this.createCircle();
        this.createItem();
    }

    public async exit(): Promise<void> {
        super.exit();
        this.removeCircle();
        this.removeItem();
    }

    //重頭開始遊戲
    protected startGame( arg?:any ){
        this.init();
        this.changeGameState(GameState.Ready);
    }

    //若斷線重連需要一半開始的遊戲, 會經由continue game進入, 使用本地暫存的進度繼續遊戲
    protected continueGame( arg?: any ){
        this.init();
        this.changeGameState(GameState.Ready);
    }
    //暫停遊戲
    protected pauseGame(){
        this.isPause = true;   
    }

    //繼續遊戲
    protected resumeGame(){
        this.isPause = false;
    }    


    protected forceEndGame(){
        //實作當玩家強制結束遊戲時, 需要做的事情
        this.changeGameState(GameState.End);
    }

    protected async goToResult(){
        if (BaseGameData.Instance.Service) {
            await BaseGameData.Instance.Service.requestGameOver(1);

            // if 有新的收集進度 (3)
            BaseGameData.Instance.Service.requestAddCollections(3, GameMode.Classic)
        }
        super.goToResult();
    }


    private onClickConfirm(){
        switch(this.gameData.state){
            case GameState.Ready:
                this.changeGameState(GameState.Playing);
                break;
            case GameState.Playing:
                this.changeGameState(GameState.End);
                break;
            case GameState.End:
                this.goToResult();
                break;
            case GameState.Non:
                break;
        }
    }

    private init(){
        this.gameData.state = GameState.Non;
        this.circle.forEach(element => {
            element.setRotationFromEuler( new Vec3(0,0,0) );
        });

        this.btn.string = "開始遊戲";
        this.info.string = "遊戲未開始";
        this.isPause = false;
        this.rotateAngle = 0;
    }

    protected update(dt: number): void {

        switch(this.gameData.state){
            case GameState.Ready:
                break;
            case GameState.Playing:
                if(this.isPause){
                    return;
                }
                this.rotateAngle+=dt*100;

                this.circle.forEach(element => {
                    element.setRotationFromEuler( new Vec3(0,0,this.rotateAngle) );
                });
                break;
            case GameState.End:
                break;
            case GameState.Non:
                break;
        }
    }


    public changeGameState(state: GameState){

        this.gameData.state = state;

        switch(this.gameData.state){
            case GameState.Ready:
                this.info.string = "遊戲準備中";
                this.btn.string = "遊戲開始";
                break;
            case GameState.Playing:
                this.info.string = "遊戲畫面";
                this.btn.string = "結束遊戲";
                break;
            case GameState.End:
                this.isPause = true;
                this.btn.string = "去結算";
                this.info.string = "遊戲勝負頁";
                break;
            case GameState.Non:
                break;
        
        }
    }

    private createCircle(){
        let circle = BasePrefabMgr.Instance.instantiatePref("circle");
        circle.setParent(this.circleRoot);
        circle.setPosition(0,0,0);
        this.circle.push(circle);
    }

    private removeCircle(){
        let circle = this.circle.pop();
        BasePrefabMgr.Instance.recycleObject("circle", circle);
    }


    private item:Node[] = [];

    private createItem(){
        let item = BasePrefabMgr.Instance.instantiatePref("item");
        item.setParent(this.circleRoot);
        item.setPosition(350,0,0);
        this.item.push(item);
    }

    private removeItem(){
        let item = this.item.pop();
        BasePrefabMgr.Instance.recycleObject("item", item);
    }

}


