import { _decorator, TextAsset, CCString } from 'cc';
import { BaseGameMain } from '@gamecommon/base/BaseGameMain';
import { BaseGameState, BaseGameEventDefine} from '@gamecommon/base/BaseGameDefine';
import { BaseGameEvent } from '@gamecommon/base/BaseGameEvent';
import { GameData } from './SampleGameData';
import { BaseGameData } from '@gamecommon/base/BaseGameData';
import { SimpleSingleGameService } from '@gamecommon/base/SimpleSingleGameService';
const { ccclass, property } = _decorator;

@ccclass('SampleConfigAsset')
class SampleConfigAsset {
    @property({ type: TextAsset })
    csv: TextAsset = null;
    @property({ type: CCString, tooltip: "描述", displayName: "描述" })
    memo: string = ""
}

// 範例文件名稱
const CONFIG_NAME = "sample_config";

class SampleConfigData {
    id: number = 0;
    data: string = "";
    msg: string = "";
}


@ccclass('SampleGameMain')
export class SampleGameMain extends BaseGameMain {

    @property({ type: [SampleConfigAsset] })
    private config: SampleConfigAsset[] = [];
    


    protected async onLoad() {
        BaseGameData.Instance.Service = new SimpleSingleGameService();

        await super.onLoad();

        // 讀取配置文件範例
        GameData.Instance.configMgr.addLoader({onLoadConfig: this.onLoadConfig.bind(this)});
        await GameData.Instance.configMgr.loadConfig(CONFIG_NAME);
    }

    protected start() {

        super.start();
        //初始化遊戲資料
        GameData.Instance.reset();

        //進入遊戲大廳
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.GAME_LOBBY, false);

        // 取出文件資料
        const config = GameData.Instance.configMgr.getConfig<SampleConfigData>(CONFIG_NAME);
        const data1 = config.data.find((data) => data.id == 1);
        console.log(`id = 1: ${data1.data} ${data1.msg}`);
        const data2 = config.data.find((data) => data.id == 2);
        console.log(`id = 2: ${data2.data} ${data2.msg}`);
    }

    

    /**
     * 加載配置文件
     * @param name 
     * @returns 
     */
    onLoadConfig(name: string): Promise<string> {
        return Promise.resolve(this.config.find((config) => config.csv.name === name).csv.text);
    }
}

